# In-memory tracking for per-email cooldowns and abuse detection
_email_last_request = {}  # email -> timestamp of last reset request
_ip_reset_counts = {}     # ip -> list of timestamps within tracking window

EMAIL_COOLDOWN_SECONDS = 60        # Min seconds between requests for same email
IP_ABUSE_WINDOW_SECONDS = 3600     # 1 hour window for IP abuse tracking
IP_ABUSE_MAX_REQUESTS = 5          # Max unique email reset requests per IP per window

