def _hash_token(token: str) -> str:
    """Hash the token before storing in DB so a DB leak doesn't expose valid tokens."""
    return hashlib.sha256(token.encode('utf-8')).hexdigest()


def _check_email_cooldown(email: str) -> bool:
    """Return True if the email is still within cooldown period."""
    normalized = email.strip().lower()
    last_ts = _email_last_request.get(normalized)
    if last_ts and (time.time() - last_ts) < EMAIL_COOLDOWN_SECONDS:
        return True
    return False


def _record_email_request(email: str):
    normalized = email.strip().lower()
    _email_last_request[normalized] = time.time()


def _check_ip_abuse(ip: str) -> bool:
    """Return True if this IP has exceeded the per-window reset request limit."""
    now = time.time()
    timestamps = _ip_reset_counts.get(ip, [])
    # Prune old entries
    timestamps = [t for t in timestamps if (now - t) < IP_ABUSE_WINDOW_SECONDS]
    _ip_reset_counts[ip] = timestamps
    return len(timestamps) >= IP_ABUSE_MAX_REQUESTS


def _record_ip_request(ip: str):
    now = time.time()
    timestamps = _ip_reset_counts.get(ip, [])
    timestamps = [t for t in timestamps if (now - t) < IP_ABUSE_WINDOW_SECONDS]
    timestamps.append(now)
    _ip_reset_counts[ip] = timestamps


