@app.route('/api/password-reset/request', methods=['POST'])
@limiter.limit("10 per minute")  # Hard rate limit at the Flask-Limiter level
def request_password_reset():
    """
    Request a password reset link.
    Always returns a generic 200 response regardless of whether the email exists,
    to prevent email enumeration.
    """
    data = request.get_json(silent=True)
    if not data or 'email' not in data:
        return jsonify({'message': 'Email is required.'}), 400

    email = data['email'].strip().lower()

    if not email or '@' not in email or len(email) > 254:
        return jsonify({'message': 'Please provide a valid email address.'}), 400

    client_ip = get_remote_address()

    # --- Abuse prevention: IP-level throttle ---
    if _check_ip_abuse(client_ip):
        # Still return generic message; don't reveal that we're blocking
        # But log it server-side for monitoring
        app.logger.warning(
            f"IP abuse threshold reached for {client_ip} on password reset"
        )
        return jsonify({'message': GENERIC_RESET_RESPONSE}), 200

    # --- Abuse prevention: per-email cooldown ---
    if _check_email_cooldown(email):
        # Don't reveal cooldown to the client; return generic response
        app.logger.info(
            f"Password reset cooldown active for email hash "
            f"{hashlib.sha256(email.encode()).hexdigest()[:12]}"
        )
        return jsonify({'message': GENERIC_RESET_RESPONSE}), 200

    # Record the request for tracking purposes (before checking if user exists)
    _record_email_request(email)
    _record_ip_request(client_ip)

    # Check if user exists — but NEVER reveal this to the caller
    user = User.query.filter_by(email=email).first()

    if user:
        # Invalidate any existing tokens for this user
        _invalidate_existing_tokens(email)

        # Generate a cryptographically secure random token
        raw_token = secrets.token_urlsafe(48)
        token_hash = _hash_token(raw_token)
        expires_at = datetime.utcnow() + timedelta(minutes=RESET_TOKEN_EXPIRY_MINUTES)

        reset_entry = PasswordResetToken(
            email=email,
            token_hash=token_hash,
            expires_at=expires_at,
            used=False,
        )
        db.session.add(reset_entry)
        db.session.commit()

        # Build the reset link (the raw token goes to the user, only the hash is stored)
        reset_link = f"https://yourapp.com/reset-password?token={raw_token}&email={email}"
        send_reset_email(email, reset_link)

        app.logger.info(f"Password reset token generated for {email}")
    else:
        app.logger.info(
            f"Password reset requested for non-existent email hash "
            f"{hashlib.sha256(email.encode()).hexdigest()[:12]}"
        )

    # Always return the same generic response
    return jsonify({'message': GENERIC_RESET_RESPONSE}), 200


@app.route('/api/password-reset/confirm', methods=['POST'])
@limiter.limit("5 per minute")  # Tight limit on confirmation attempts
def confirm_password_reset():
    """
    Confirm a password reset using the token and set a new password.
    """
    data = request.get_json(silent=True)
    if not data:
        return jsonify({'message': 'Invalid request.'}), 400

    token = data.get('token', '').strip()
    email = data.get('email', '').strip().lower()
    new_password = data.get('new_password', '')

    if not token or not email or not new_password:
        return jsonify({'message': 'Token, email, and new password are required.'}), 400

    if len(new_password) < 8:
        return jsonify({'message': 'Password must be at least 8 characters.'}), 400

    if len(new_password) > 128:
        return jsonify({'message': 'Password is too long.'}), 400

    token_hash = _hash_token(token)

    reset_entry = PasswordResetToken.query.filter_by(
        token_hash=token_hash,
        email=email,
        used=False,
    ).first()

    if not reset_entry:
        app.logger.warning(
            f"Invalid or expired reset token attempt for email hash "
            f"{hashlib.sha256(email.encode()).hexdigest()[:12]} from {get_remote_address()}"
        )
        return jsonify({'message': 'Invalid or expired reset token.'}), 400

    if datetime.utcnow() > reset_entry.expires_at:
        reset_entry.used = True
        db.session.commit()
        return jsonify({'message': 'Invalid or expired reset token.'}), 400

    # Mark token as used
    reset_entry.used = True

    # Update the user's password
    user = User.query.filter_by(email=email).first()
    if not user:
        db.session.commit()
        return jsonify({'message': 'Invalid or expired reset token.'}), 400

    # Hash the new password (use a proper password hashing library in production)
    from werkzeug.security import generate_password_hash
    user.password_hash = generate_password_hash(new_password)

    # Invalidate all other tokens for this user
    PasswordResetToken.query.filter(
        PasswordResetToken.email == email,
        PasswordResetToken.id != reset_entry.id,
        PasswordResetToken.used == False,
    ).update({'used': True})

    db.session.commit()

    app.logger.info(f"Password successfully reset for {email}")
    return jsonify({'message': 'Password has been reset successfully.'}), 200


